import{_ as e,o as s,c as a,ah as n}from"./chunks/framework.DE8HRBTl.js";const g=JSON.parse('{"title":"Neo 开发助手 Skills","description":"","frontmatter":{},"headers":[],"relativePath":"guide/devSkills.md","filePath":"guide/devSkills.md"}'),l={name:"guide/devSkills.md"};function i(o,t,d,p,r,c){return s(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="neo-开发助手-skills" tabindex="-1">Neo 开发助手 Skills <a class="header-anchor" href="#neo-开发助手-skills" aria-label="Permalink to &quot;Neo 开发助手 Skills&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Beta 状态</p><p>本「开发助手 Skills」目前处于 <strong>Beta</strong> 阶段，功能和使用方式仍在持续打磨中。试用过程中发现任何问题，或有改进建议，欢迎随时反馈到 <a href="https://github.com/xsy-neoui/neo-cmp-docs/issues" target="_blank" rel="noreferrer">neo-cmp-docs Issues</a>。</p></div><h2 id="什么是-neo-开发助手-skills" tabindex="-1">什么是 Neo 开发助手 Skills <a class="header-anchor" href="#什么是-neo-开发助手-skills" aria-label="Permalink to &quot;什么是 Neo 开发助手 Skills&quot;">​</a></h2><p>一套 AI 辅助开发工具，让你在 AI 编辑器（如 Kiro、Cursor）中通过对话完成 NeoCRM PaaS 平台的定制开发。AI 理解平台的 SDK、API 规范和开发约束，能帮你做方案设计、生成代码、部署验证。</p><h2 id="环境准备" tabindex="-1">环境准备 <a class="header-anchor" href="#环境准备" aria-label="Permalink to &quot;环境准备&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">依赖</th><th style="text-align:left;">安装方式</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">Node.js</td><td style="text-align:left;"><a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a></td><td style="text-align:left;">运行脚本和 neo-cmp-cli</td></tr><tr><td style="text-align:left;">neo-cmp-cli</td><td style="text-align:left;"><code>npm i -g neo-cmp-cli</code></td><td style="text-align:left;">项目创建、登录、组件发布</td></tr></tbody></table><p>验证安装：<code>neo -v</code></p><h2 id="适用人群" tabindex="-1">适用人群 <a class="header-anchor" href="#适用人群" aria-label="Permalink to &quot;适用人群&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">角色</th><th style="text-align:left;">典型诉求</th></tr></thead><tbody><tr><td style="text-align:left;">内部</td><td style="text-align:left;">售前顾问</td><td style="text-align:left;">快速搭建 Demo 环境，向客户演示定制能力</td></tr><tr><td style="text-align:left;">内部</td><td style="text-align:left;">业务顾问</td><td style="text-align:left;">将业务需求转化为可落地的技术方案，减少与开发的沟通成本</td></tr><tr><td style="text-align:left;">内部</td><td style="text-align:left;">技术经理</td><td style="text-align:left;">对已经清晰的技术方案进行快速落地，提高交付效率</td></tr><tr><td style="text-align:left;">外部</td><td style="text-align:left;">企业管理员</td><td style="text-align:left;">梳理业务场景并自动落地，降低技术门槛</td></tr><tr><td style="text-align:left;">外部</td><td style="text-align:left;">合作伙伴</td><td style="text-align:left;">基于 PaaS 平台交付客户项目，加速开发效率</td></tr></tbody></table><blockquote><p>无需编程经验即可使用方案设计和实体管理技能包；后端/前端开发技能包建议具备基础的 Java 或 React 知识。</p></blockquote><h2 id="典型使用场景" tabindex="-1">典型使用场景 <a class="header-anchor" href="#典型使用场景" aria-label="Permalink to &quot;典型使用场景&quot;">​</a></h2><h3 id="场景-1-设计-创建业务对象" tabindex="-1">场景 1：设计 + 创建业务对象 <a class="header-anchor" href="#场景-1-设计-创建业务对象" aria-label="Permalink to &quot;场景 1：设计 + 创建业务对象&quot;">​</a></h3><blockquote><p>你说：&quot;我要管理投标项目，帮我设计实体模型并创建出来&quot;</p></blockquote><p><strong>涉及技能包</strong>：neo-solution-design → neo-entity-management</p><p><strong>AI 会做什么</strong>：</p><ol><li>引导你描述业务场景（投标有哪些阶段？需要记录哪些信息？）</li><li>生成实体模型设计文档（实体名、字段列表、关联关系）</li><li>确认后通过 Metadata API 在租户中自动创建实体和字段</li></ol><p><strong>产出</strong>：</p><ul><li>方案文档：<code>solutions/bid-management/design.md</code></li><li>租户中已创建的实体和字段，可直接在 CRM 界面使用</li></ul><p><strong>价值</strong>：传统方式需要业务顾问写需求 → 开发建模 → 手动配置，耗时 1-2 天。使用技能包后，一次对话即可完成从需求梳理到实体落地，约 10 分钟。</p><h3 id="场景-2-开发一个数据看板" tabindex="-1">场景 2：开发一个数据看板 <a class="header-anchor" href="#场景-2-开发一个数据看板" aria-label="Permalink to &quot;场景 2：开发一个数据看板&quot;">​</a></h3><blockquote><p>你说：&quot;帮我做一个商机阶段分布的统计卡片组件&quot;</p></blockquote><p><strong>涉及技能包</strong>：neo-frontend-dev（可选先走 neo-solution-design）</p><p><strong>AI 会做什么</strong>：</p><ol><li>确认数据来源（查询哪个实体、按什么维度统计）</li><li>生成 React + AntD 组件代码（含数据查询、图表渲染、样式）</li><li>执行 <code>neo push cmp</code> 发布到租户</li></ol><p><strong>产出</strong>：</p><ul><li>组件代码：<code>src/components/opportunityStatsCard__c/</code></li><li>租户中可用的自定义组件，可拖拽到首页或详情页</li></ul><p><strong>价值</strong>：前端开发者通常需要查阅组件规范、调试接口、处理发布流程，整个过程 2-4 小时。技能包将规范内置，AI 一次性生成符合平台要求的代码并完成发布，约 15 分钟。</p><h3 id="场景-3-完整功能模块从设计到落地" tabindex="-1">场景 3：完整功能模块从设计到落地 <a class="header-anchor" href="#场景-3-完整功能模块从设计到落地" aria-label="Permalink to &quot;场景 3：完整功能模块从设计到落地&quot;">​</a></h3><blockquote><p>你说：&quot;我要做一个项目管理模块，包含项目、里程碑、任务三个对象，项目关闭时自动归档所有任务&quot;</p></blockquote><p><strong>涉及技能包</strong>：neo-solution-design → neo-entity-management → neo-backend-dev → neo-frontend-dev → neo-task-summary</p><p><strong>AI 会做什么</strong>：</p><ol><li><strong>需求分析</strong>：梳理三个实体的字段、关联关系、业务规则</li><li><strong>技术设计</strong>：输出 design.md，拆分为可执行的任务列表</li><li><strong>创建实体</strong>：通过 API 创建 project__c、milestone__c、task__c 及其字段</li><li><strong>后端开发</strong>：编写&quot;项目关闭时归档任务&quot;的 Trigger，配置并部署</li><li><strong>前端开发</strong>：开发项目看板组件，发布到租户</li><li><strong>生成总结</strong>：输出本次开发的回顾文档，记录决策和问题</li></ol><p><strong>产出</strong>：</p><ul><li>方案文档：<code>solutions/project-management/</code>（requirements.md + design.md + tasks.md）</li><li>租户中 3 个实体 + 字段 + Trigger + 前端组件</li><li>开发总结：<code>summaries/项目管理模块-20250512.md</code></li></ul><p><strong>价值</strong>：一个完整功能模块从需求到上线，传统方式需要产品出文档 → 开发排期 → 编码 → 测试 → 部署，通常 1-2 周。使用技能包后，技术经理或合作伙伴可以在 1-2 小时内完成全链路交付。</p><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="_1-在-ai-编辑器中安装技能包" tabindex="-1">1. 在 AI 编辑器中安装技能包 <a class="header-anchor" href="#_1-在-ai-编辑器中安装技能包" aria-label="Permalink to &quot;1. 在 AI 编辑器中安装技能包&quot;">​</a></h3><p>可通过下载技能包手动安装到 AI 编辑器（CodeBuddy、Kiro、Cursor等）中。</p><h3 id="下载技能包" tabindex="-1">下载技能包 <a class="header-anchor" href="#下载技能包" aria-label="Permalink to &quot;下载技能包&quot;">​</a></h3><ul><li><strong>点击下载</strong>：<a href="/neo-cmp-docs/html/devSkills.zip">devSkills.zip</a>。</li></ul><p>技能包内包含以下技能：</p><table tabindex="0"><thead><tr><th>Skill</th><th>作用</th></tr></thead><tbody><tr><td><code>neo-frontend-dev</code></td><td>React 16 + TypeScript 自定义组件开发（基于 neo-cmp-cli 工具链）</td></tr><tr><td><code>neo-backend-dev</code></td><td>Java 后端代码全流程开发</td></tr><tr><td><code>neo-entity-management</code></td><td>查询和管理平台实体元数据，支持通过 Metadata API 自动创建实体和字段</td></tr><tr><td><code>neo-solution-design</code></td><td>从需求到方案的全流程引导</td></tr><tr><td><code>neo-task-summary</code></td><td>任务完成后生成结构化回顾文档</td></tr></tbody></table><h3 id="手动安装步骤" tabindex="-1">手动安装步骤 <a class="header-anchor" href="#手动安装步骤" aria-label="Permalink to &quot;手动安装步骤&quot;">​</a></h3><p>根据你使用的 AI 编辑器，将 <code>devSkills.zip</code> 解压得到的 skill 添加导入到对应的 AI 编辑器（CodeBuddy、Kiro、Cursor等）即可。</p><p>以 CodeBuddy 为例，skill 添加导入步骤如下：</p><ol><li>在「技能」页面，点击右上角的「+ 添加技能」按钮，选择「上传技能」；</li><li>选择 <code>devSkills.zip</code> 解压得到的 <code>neo-frontend-dev</code> 目录（devSkills/neo-frontend-dev），点击「确定」；</li><li>重复步骤 1、2 导入 <code>neo-backend-dev</code>、<code>neo-entity-management</code>、<code>neo-solution-design</code>、<code>neo-task-summary</code> 四个 skill。</li></ol><div class="tip custom-block"><p class="custom-block-title">覆盖说明</p><p>若目标目录中已有同名 skill，覆盖式写入即可。</p></div><h3 id="_2-创建项目" tabindex="-1">2. 创建项目 <a class="header-anchor" href="#_2-创建项目" aria-label="Permalink to &quot;2. 创建项目&quot;">​</a></h3><p>对 AI 说：</p><blockquote><p>&quot;帮我创建一个 Neo 项目&quot;</p></blockquote><p>AI 会执行 <code>neo create project</code> 并引导你登录租户。</p><h3 id="_3-开始开发" tabindex="-1">3. 开始开发 <a class="header-anchor" href="#_3-开始开发" aria-label="Permalink to &quot;3. 开始开发&quot;">​</a></h3><p>直接描述你的需求，AI 会自动选择合适的技能包：</p><table tabindex="0"><thead><tr><th style="text-align:left;">你说的话</th><th style="text-align:left;">AI 使用的技能包</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;帮我做一个客户查重功能&quot;</td><td style="text-align:left;">neo-solution-design → neo-backend-dev</td></tr><tr><td style="text-align:left;">&quot;开发一个商机看板组件&quot;</td><td style="text-align:left;">neo-solution-design → neo-frontend-dev</td></tr><tr><td style="text-align:left;">&quot;写一个 Trigger，商机关闭时更新客户状态&quot;</td><td style="text-align:left;">neo-backend-dev</td></tr><tr><td style="text-align:left;">&quot;查一下 account 实体有哪些字段&quot;</td><td style="text-align:left;">neo-entity-management</td></tr><tr><td style="text-align:left;">&quot;总结一下这次的开发&quot;</td><td style="text-align:left;">neo-task-summary</td></tr></tbody></table><h2 id="技能包说明" tabindex="-1">技能包说明 <a class="header-anchor" href="#技能包说明" aria-label="Permalink to &quot;技能包说明&quot;">​</a></h2><h3 id="neo-solution-design-方案设计" tabindex="-1">neo-solution-design（方案设计） <a class="header-anchor" href="#neo-solution-design-方案设计" aria-label="Permalink to &quot;neo-solution-design（方案设计）&quot;">​</a></h3><p>从需求到方案的全流程引导。</p><p><strong>适用场景</strong>：新功能开发、老功能迭代、不确定技术方案时</p><p><strong>流程</strong>：需求收集 → 技术设计 → 任务拆分</p><p><strong>产出</strong>：<code>solutions/{feature-name}/</code> 下的 requirements.md、design.md、tasks.md</p><p><strong>使用方式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;帮我设计一个项目管理模块的方案&quot;</span></span>
<span class="line"><span>&quot;我要做一个定时同步数据的功能，帮我分析一下&quot;</span></span></code></pre></div><h3 id="neo-backend-dev-后端开发" tabindex="-1">neo-backend-dev（后端开发） <a class="header-anchor" href="#neo-backend-dev-后端开发" aria-label="Permalink to &quot;neo-backend-dev（后端开发）&quot;">​</a></h3><p>Java 后端代码全流程开发。</p><p><strong>支持的扩展类型</strong>：</p><ul><li>Trigger 触发器（before/after，支持 add/update/delete/transfer 等）</li><li>自定义 REST API（@RestApi + @RestMapping）</li><li>计划作业（ScheduleJob + BatchJobService）</li><li>流程扩展（审批事件 / 自动流 / 规则事件）</li><li>异步任务（FutureTask）</li><li>AI 提示词模板调用</li></ul><p><strong>使用方式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;帮我写一个 Trigger，客户创建后自动分配负责人&quot;</span></span>
<span class="line"><span>&quot;开发一个 API，根据员工姓名查询积分详情&quot;</span></span>
<span class="line"><span>&quot;部署代码包 other.xsy.account&quot;</span></span></code></pre></div><p><strong>代码存放位置</strong>：<code>src/codePackages/{代码包简称}/other/{company}/{module}/</code></p><p><strong>部署命令</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> neo-backend-dev/scripts/deploy_server_script.js</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">项目目</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">录</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">代码包简</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">称</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Java包</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">名</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h3 id="neo-frontend-dev-前端开发" tabindex="-1">neo-frontend-dev（前端开发） <a class="header-anchor" href="#neo-frontend-dev-前端开发" aria-label="Permalink to &quot;neo-frontend-dev（前端开发）&quot;">​</a></h3><p>React 16 + TypeScript 自定义组件开发（基于 neo-cmp-cli 工具链）。</p><p><strong>核心能力</strong>：</p><ul><li>11 步开发流程（需求分析→实体识别→数据接入→组件实现→发布）</li><li>平台数据源对接（xObject / customApi / 通用代理）</li><li>事件动作机制（@NeoEvent + BaseCmp）</li><li>平台预置组件（NeoEntityList / NeoEntityGrid）</li><li>propsSchema 属性面板配置</li></ul><p><strong>使用方式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;帮我开发一个商机统计卡片组件&quot;</span></span>
<span class="line"><span>&quot;拉取系统中的 pipelineWidget__c 组件并修改&quot;</span></span>
<span class="line"><span>&quot;发布组件 statsCard__c&quot;</span></span></code></pre></div><p><strong>组件存放位置</strong>：<code>src/components/{组件名}__c/</code></p><p><strong>发布命令</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cmp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">组件</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">名</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h3 id="neo-entity-management-实体管理" tabindex="-1">neo-entity-management（实体管理） <a class="header-anchor" href="#neo-entity-management-实体管理" aria-label="Permalink to &quot;neo-entity-management（实体管理）&quot;">​</a></h3><p>查询和管理平台实体元数据，支持通过 Metadata API 自动创建实体和字段。</p><p><strong>支持的操作</strong>：</p><ul><li>查询实体列表和字段定义</li><li>创建自定义实体（文本/自动编号主字段）</li><li>创建 19 种字段类型（文本、单选、多选、整数、金额、日期、日期时间、电话、邮箱、网址、图片、布尔、地理位置、百分比、关联关系、查找字段、文件、富文本等）</li><li>创建业务类型</li><li>查询实体间关联关系</li></ul><p><strong>使用方式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;查一下系统里有哪些实体&quot;</span></span>
<span class="line"><span>&quot;查询 opportunity 实体的字段定义&quot;</span></span>
<span class="line"><span>&quot;创建一个招投标项目实体，包含预算金额、截止日期、状态等字段&quot;</span></span></code></pre></div><p><strong>本地缓存位置</strong>：</p><ul><li>实体列表：<code>src/xObjects/AllxObjects.md</code></li><li>字段定义：<code>src/xObjects/fields/{apiKey}.md</code></li></ul><h3 id="neo-task-summary-任务总结" tabindex="-1">neo-task-summary（任务总结） <a class="header-anchor" href="#neo-task-summary-任务总结" aria-label="Permalink to &quot;neo-task-summary（任务总结）&quot;">​</a></h3><p>任务完成后生成结构化回顾文档。</p><p><strong>触发方式</strong>：对 AI 说&quot;总结一下&quot;、&quot;回顾&quot;、&quot;写个总结&quot;</p><p><strong>产出位置</strong>：<code>summaries/{任务简述}-{YYYYMMDD}.md</code></p><p><strong>文档结构</strong>：</p><ol><li>任务背景（做了什么、为什么做）</li><li>最终结果（产出、部署状态）</li><li>过程问题（意图 → 问题 → 解法）</li></ol><h2 id="项目目录结构" tabindex="-1">项目目录结构 <a class="header-anchor" href="#项目目录结构" aria-label="Permalink to &quot;项目目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的项目/</span></span>
<span class="line"><span>├── neo.config.js              # 项目配置</span></span>
<span class="line"><span>├── .neo-cli/token.json        # 登录凭证</span></span>
<span class="line"><span>├── solutions/                 # 方案设计文档</span></span>
<span class="line"><span>│   └── {feature-name}/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── components/            # 前端自定义组件</span></span>
<span class="line"><span>│   │   └── xxxWidget__c/</span></span>
<span class="line"><span>│   ├── xObjects/              # 实体元数据缓存</span></span>
<span class="line"><span>│   │   ├── AllxObjects.md</span></span>
<span class="line"><span>│   │   └── fields/{apiKey}.md</span></span>
<span class="line"><span>│   └── codePackages/          # 后端代码包</span></span>
<span class="line"><span>│       └── {代码包简称}/</span></span>
<span class="line"><span>│           ├── other/{company}/{module}/</span></span>
<span class="line"><span>│           │   ├── triggers/</span></span>
<span class="line"><span>│           │   ├── apis/</span></span>
<span class="line"><span>│           │   ├── schedules/</span></span>
<span class="line"><span>│           │   ├── flows/</span></span>
<span class="line"><span>│           │   └── utils/</span></span>
<span class="line"><span>│           ├── scriptTrigger.xml</span></span>
<span class="line"><span>│           └── doc.md</span></span>
<span class="line"><span>└── summaries/                 # 任务总结</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: AI 直接开始写代码，没有先做方案设计怎么办？</strong></p><p>技能包已内置前置检查：如果没有 tasks.md，AI 会提示你先走方案设计。如果你确定不需要方案设计，告诉 AI &quot;跳过方案设计，直接开发&quot;。</p><p><strong>Q: 部署时报 SSL 证书错误？</strong></p><p>在命令前加环境变量：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NODE_TLS_REJECT_UNAUTHORIZED</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> neo-backend-dev/scripts/deploy_server_script.js</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span></code></pre></div><p><strong>Q: 部署 Trigger 时报 order 冲突？</strong></p><p>将 scriptTrigger.xml 中对应 <code>&lt;order&gt;</code> 的值 +1 后重新部署。</p><p><strong>Q: 如何确认实体的正确 API Key？</strong></p><p>对 AI 说&quot;查一下系统里有哪些实体&quot;，或直接查看 <code>src/xObjects/AllxObjects.md</code>。</p><p><strong>Q: 后端代码包的 Java 包名规则是什么？</strong></p><ul><li>前三级：<code>other.{company}.{module}</code>（如 <code>other.xsy.account</code>），全部小写</li><li>第四级可选：<code>triggers</code> / <code>apis</code> / <code>schedules</code> / <code>flows</code> / <code>utils</code></li><li>部署时只用三级包名</li></ul><p><strong>Q: npm install 很慢怎么办？</strong></p><p>后端代码部署不需要 npm install。前端组件发布前才需要，技能包会自动加淘宝源 <code>--registry=https://registry.npmmirror.com</code> 加速安装。</p><h2 id="反馈与改进" tabindex="-1">反馈与改进 <a class="header-anchor" href="#反馈与改进" aria-label="Permalink to &quot;反馈与改进&quot;">​</a></h2><p>使用过程中遇到问题或有优化建议，可以在任务完成后对 AI 说&quot;总结一下&quot;，生成的总结文件会记录问题和解法，方便后续反馈给技能包维护者。</p>`,112)])])}const u=e(l,[["render",i]]);export{g as __pageData,u as default};
